        // ── 克隆按钮异步处理 ──
        async Task OnCloneClickAsync()
        {
            if (_isCloning) return;
            if (string.IsNullOrWhiteSpace(_cloneAudioPath))
            {
                _cloneStatus = "请填写源音频文件路径";
                return;
            }
            if (string.IsNullOrWhiteSpace(_cloneVoiceName))
            {
                _cloneStatus = "请填写音色名称";
                return;
            }

            _isCloning = true;
            _cloneStatus = "正在上传并克隆音色...";
            StateHasChanged();

            try
            {
                var cfg = Configuration;
                var result = await MiniMaxTTSModel.CloneVoiceStaticAsync(
                    cfg,
                    _cloneAudioPath,
                    _cloneVoiceName,
                    string.IsNullOrWhiteSpace(_clonePromptPath) ? null : _clonePromptPath,
                    string.IsNullOrWhiteSpace(_clonePromptText) ? null : _clonePromptText);

                _cloneStatus = result == null
                    ? $"✅ 克隆成功！已自动切换音色为「{_cloneVoiceName}」"
                    : $"❌ {result}";
            }
            catch (Exception ex)
            {
                _cloneStatus = $"❌ 克隆异常：{ex.Message}";
            }
            finally
            {
                _isCloning = false;
                StateHasChanged();
            }
        }

