            b.AddAttribute(_s++, "style", "margin-top:12px");
            b.OpenElement(_s++, "div");
            b.AddAttribute(_s++, "style", "font-size:13px;color:#333;margin-bottom:4px");
            b.AddContent(_s++, label);
            b.CloseElement();
            b.OpenElement(_s++, "div");
            b.AddAttribute(_s++, "style", "display:flex;align-items:center;gap:8px");
            b.OpenComponent<Slider<double>>(_s++);
            b.AddComponentParameter(_s++, "Value", value);
            b.AddComponentParameter(_s++, "ValueChanged",
                EventCallback.Factory.Create<double>(this, setter));
            b.AddComponentParameter(_s++, "Min", min);
            b.AddComponentParameter(_s++, "Max", max);
            b.AddComponentParameter(_s++, "Step", step);
            b.AddComponentParameter(_s++, "Style", "width:200px");
            b.CloseComponent();
            b.AddContent(_s++, $"{value:F1}{suffix}");
            b.CloseElement();
            b.CloseElement();
        }

        void RenderVoiceButtons(RenderTreeBuilder b, string title,
            (string label, string id)[] voices)
        {
            b.OpenElement(_s++, "div");
            b.AddAttribute(_s++, "style", "margin-top:8px");
            b.OpenElement(_s++, "div");
            b.AddAttribute(_s++, "style", "display:flex;flex-wrap:wrap;gap:4px");
            foreach (var v in voices)
            {
                var voiceId = v.id; // 局部变量避免闭包共享
                b.OpenComponent<Button>(_s++);
                b.AddComponentParameter(_s++, "Size", ButtonSize.Small);
                b.AddComponentParameter(_s++, "OnClick",
                    EventCallback.Factory.Create<Microsoft.AspNetCore.Components.Web.MouseEventArgs>(
                        this, _ => Configuration!.VoiceId = voiceId));
                b.AddAttribute(_s++, "ChildContent", (RenderFragment)((b2) =>
                {
                    b2.AddContent(_s++, v.label);
                }));
                b.CloseComponent();
            }
            b.CloseElement();
            b.CloseElement();
        }
    }
}
